import{_ as i,c as a,o as e,ah as t}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/nautilus_trader-开发工具.md","filePath":"github汇总/开发工具/nautilus_trader-开发工具.md"}'),r={name:"github汇总/开发工具/nautilus_trader-开发工具.md"};function s(n,l,o,h,u,c){return e(),a("div",null,l[0]||(l[0]=[t(`<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>NautilusTrader</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Nautech Systems</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>量化交易者需要在历史数据上回测自动化交易策略，并将这些策略部署到实盘交易，传统方法需要在不同环境中重写代码，效率低下且容易出错。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>高性能事件驱动的回测引擎</li><li>无代码变更地将策略部署到实盘交易</li><li>支持多种资产类别：外汇、股票、期货、期权、加密货币、DeFi和博彩</li><li>多场所同时操作能力</li><li>高级订单类型和条件触发</li><li>可定制的组件和系统</li><li>AI训练支持</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>核心用Rust编写，性能优异</li><li>异步网络通信使用tokio</li><li>跨平台兼容，支持Linux、macOS和Windows</li><li>模块化设计，支持任何REST API或WebSocket feed集成</li><li>提供Python原生环境，便于数据科学和AI集成</li><li>开源免费，采用GNU Lesser General Public License v3.0</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/nautechsystems/nautilus_trader" target="_blank" rel="noreferrer">https://github.com/nautechsystems/nautilus_trader</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于量化交易者和开发者，需要在历史数据上回测交易策略并部署到实盘交易。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>系统要求：Linux、macOS或Windows</li><li>Python版本：3.12-3.14</li><li>依赖：Rust（从源代码构建时需要）</li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><h3 id="从pypi安装" tabindex="-1">从PyPI安装 <a class="header-anchor" href="#从pypi安装" aria-label="Permalink to “从PyPI安装”">​</a></h3><ol><li><p><strong>安装最新版本</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>pip install -U nautilus_trader</code></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查Python版本是否符合要求</li></ul></li><li><p><strong>安装可选依赖</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>pip install -U &quot;nautilus_trader[docker,ib]&quot;</code></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查网络连接</li></ul></li></ol><h3 id="从nautech-systems包索引安装" tabindex="-1">从Nautech Systems包索引安装 <a class="header-anchor" href="#从nautech-systems包索引安装" aria-label="Permalink to “从Nautech Systems包索引安装”">​</a></h3><ol><li><p><strong>安装稳定版本</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>pip install -U nautilus_trader --index-url=https://packages.nautechsystems.io/simple</code></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查网络连接</li></ul></li><li><p><strong>安装开发版本</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>pip install -U nautilus_trader --pre --index-url=https://packages.nautechsystems.io/simple</code></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查网络连接</li></ul></li></ol><h3 id="从源代码构建" tabindex="-1">从源代码构建 <a class="header-anchor" href="#从源代码构建" aria-label="Permalink to “从源代码构建”">​</a></h3><ol><li><p><strong>安装rustup</strong></p><ul><li>执行位置：终端</li><li>完整命令： <ul><li>Linux和macOS：<code>curl https://sh.rustup.rs -sSf | sh</code></li><li>Windows：下载并安装rustup-init.exe</li></ul></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查网络连接</li></ul></li><li><p><strong>验证Rust安装</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>rustc --version</code></li><li>成功标志：显示Rust版本</li><li>失败处理：检查rustup是否正确安装</li></ul></li><li><p><strong>安装clang</strong></p><ul><li>执行位置：终端</li><li>完整命令： <ul><li>Linux：<code>sudo apt-get install clang</code></li><li>macOS：<code>xcode-select --install</code></li><li>Windows：在Visual Studio Installer中添加&quot;C++ Clang tools for Windows&quot;</li></ul></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查系统权限</li></ul></li><li><p><strong>验证clang安装</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>clang --version</code></li><li>成功标志：显示clang版本</li><li>失败处理：检查clang是否正确安装</li></ul></li><li><p><strong>安装uv</strong></p><ul><li>执行位置：终端</li><li>完整命令： <ul><li>Linux和macOS：<code>curl -LsSf https://astral.sh/uv/install.sh | sh</code></li><li>Windows：<code>irm https://astral.sh/uv/install.ps1 | iex</code></li></ul></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查网络连接</li></ul></li><li><p><strong>克隆源代码</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>git clone --branch develop --depth 1 https://github.com/nautechsystems/nautilus_trader</code></li><li>成功标志：仓库克隆成功</li><li>失败处理：检查网络连接</li></ul></li><li><p><strong>安装依赖</strong></p><ul><li>执行位置：项目目录</li><li>完整命令：<code>cd nautilus_trader &amp;&amp; uv sync --all-extras</code></li><li>成功标志：依赖安装完成，无错误信息</li><li>失败处理：检查网络连接</li></ul></li><li><p><strong>设置环境变量（Linux和macOS）</strong></p><ul><li>执行位置：终端</li><li>完整命令：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># Linux only</span></span>
<span class="line"><span>export LD_LIBRARY_PATH=&quot;$(python -c &#39;import sys; print(sys.base_prefix)&#39;)/lib:$LD_LIBRARY_PATH&quot;</span></span>
<span class="line"><span># All systems</span></span>
<span class="line"><span>export PYO3_PYTHON=$(pwd)/.venv/bin/python</span></span>
<span class="line"><span>export PYTHONHOME=$(python -c &quot;import sys; print(sys.base_prefix)&quot;)</span></span></code></pre></div></li><li>成功标志：环境变量设置成功</li><li>失败处理：检查Python路径是否正确</li></ul></li></ol><h3 id="使用docker" tabindex="-1">使用Docker <a class="header-anchor" href="#使用docker" aria-label="Permalink to “使用Docker”">​</a></h3><ol><li><p><strong>拉取Docker镜像</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>docker pull ghcr.io/nautechsystems/&lt;image_variant_tag&gt; --platform linux/amd64</code></li><li>成功标志：镜像拉取完成，无错误信息</li><li>失败处理：检查Docker是否正常运行</li></ul></li><li><p><strong>运行JupyterLab容器</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>docker run -p 8888:8888 ghcr.io/nautechsystems/jupyterlab:nightly</code></li><li>成功标志：容器启动成功，无错误信息</li><li>失败处理：检查端口是否被占用</li></ul></li><li><p><strong>访问JupyterLab</strong></p><ul><li>执行位置：浏览器</li><li>操作：访问 <a href="http://127.0.0.1:8888/lab" target="_blank" rel="noreferrer">http://127.0.0.1:8888/lab</a></li><li>成功标志：JupyterLab界面加载成功</li><li>失败处理：检查容器是否正常运行</li></ul></li></ol><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li>执行命令：<code>python -c &quot;import nautilus_trader; print(nautilus_trader.__version__)&quot;</code></li><li>预期返回：显示NautilusTrader版本</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>安装失败</strong></p><ul><li>现象：执行安装命令后出现错误</li><li>可能原因：Python版本不匹配、依赖冲突</li><li>解决步骤：检查Python版本，使用虚拟环境安装</li></ul></li><li><p><strong>从源代码构建失败</strong></p><ul><li>现象：执行构建命令后出现错误</li><li>可能原因：Rust版本过低、缺少依赖</li><li>解决步骤：更新Rust到最新版本，安装所有必要依赖</li></ul></li><li><p><strong>Docker容器启动失败</strong></p><ul><li>现象：执行docker run命令后容器状态为exited</li><li>可能原因：端口被占用、镜像损坏</li><li>解决步骤：检查端口占用情况，重新拉取镜像</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><p>使用Docker容器部署，适合快速开始和隔离环境。</p><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README/仓库信息中未提供完整的策略开发教程，上述教程基于README中提到的安装方式整理。</p>`,38)]))}const g=i(r,[["render",s]]);export{p as __pageData,g as default};
